import { NextApiRequest, NextApiResponse } from 'next';

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  const { method, query } = req;
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  if (method === 'GET' && !query.id) {
    // GET /api/users?role=...
    const users = [{ id: '1', name: 'Test User', role: query.role || 'user' }];
    return res.json(users);
  }
  if (method === 'GET' && query.id) {
    // GET /api/users/:id
    return res.json({ id: query.id, name: 'Test User' });
  }
  if (method === 'POST') {
    // POST /api/users
    const { name, email, role } = req.body;
    return res.status(201).json({ id: 'new-id', name, email, role });
  }
  if (method === 'PUT' && query.id) {
    // PUT /api/users/:id
    return res.json({ id: query.id, ...req.body });
  }
  if (method === 'DELETE' && query.id) {
    // DELETE /api/users/:id
    return res.status(204).end();
  }
  return res.status(405).end();
}
